2480	//   - bind:    ORDAIN on rbev-bottle-plantuml (digest-pinned upstream)
2481	//   - graft:   ORDAIN on rbev-graft-demo with BURE_TWEAK pointing at a local image
2482	//   - kludge:  KLUDGE on rbev-busybox (local-only, no GAR)
2483	//
2484	// Graft uses `busybox:latest` pulled from upstream as its source image — any
2485	// locally-present docker image works, and upstream busybox keeps this case
2486	// independent of conjure.
2487	
2488	const RBTDRC_FOURMODE_CONJURE_VESSEL_DIR: &str = "rbev-vessels/rbev-busybox";
