2494	fn rbtdrc_fourmode_conjure_lifecycle(dir: &Path) -> rbtdre_Verdict {
2495	    rbtdrc_with_ctx(|ctx| {
2496	        let vessel_dir = RBTDRC_FOURMODE_CONJURE_VESSEL_DIR;
2497	        if !ctx.project_root().join(vessel_dir).is_dir() {
2498	            return rbtdre_Verdict::Fail(format!("vessel directory not found: {}", vessel_dir));
2499	        }
2500	
2501	        let _ = std::fs::write(dir.join("01-ordain.txt"), "ordaining conjure");
2502	        let ordain_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ORDAIN, &[vessel_dir], &[]) {
2503	            Ok(r) if r.exit_code == 0 => r,
2504	            Ok(r) => return rbtdre_Verdict::Fail(format!("conjure ordain failed (exit {})\n{}", r.exit_code, r.stderr)),
2505	            Err(e) => return rbtdre_Verdict::Fail(format!("conjure ordain invocation: {}", e)),
2506	        };
2507	        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
2508	            Ok(v) => v,
2509	            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
2510	        };
2511	        let gar_root = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_GAR_ROOT) {
2512	            Ok(v) => v,
2513	            Err(e) => return rbtdre_Verdict::Fail(format!("read gar_root: {}", e)),
2514	        };
2515	        let ark_stem = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_ARK_STEM) {
2516	            Ok(v) => v,
2517	            Err(e) => return rbtdre_Verdict::Fail(format!("read ark_stem: {}", e)),
2518	        };
2519	        let _ = std::fs::write(dir.join("01-hallmark.txt"), &hallmark);
2520	
2521	        // Wrest locator is relative-to-cloud-prefix (rbfr_wrest prepends).
2522	        let _ = std::fs::write(dir.join("02-wrest.txt"), "wresting");
2523	        let locator = format!(
2524	            "{}/{}/{}:{}",
2525	            RBTDRC_GAR_CATEGORY_HALLMARKS, hallmark, RBTDRC_ARK_BASENAME_IMAGE, hallmark
2526	        );
2527	        match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE, &[&locator], &[]) {
2528	            Ok(r) if r.exit_code == 0 => {}
2529	            Ok(r) => return rbtdre_Verdict::Fail(format!("wrest failed (exit {})\n{}", r.exit_code, r.stderr)),
2530	            Err(e) => return rbtdre_Verdict::Fail(format!("wrest invocation: {}", e)),
2531	        }
2532	
2533	        // Local ark refs share gar_root/ark_stem; only basename differs.
2534	        let image_ref = format!(
2535	            "{}/{}/{}:{}",
2536	            gar_root, ark_stem, RBTDRC_ARK_BASENAME_IMAGE, hallmark
2537	        );
2538	        let about_ref = format!(
2539	            "{}/{}/{}:{}",
2540	            gar_root, ark_stem, RBTDRC_ARK_BASENAME_ABOUT, hallmark
2541	        );
2542	        let vouch_ref = format!(
2543	            "{}/{}/{}:{}",
2544	            gar_root, ark_stem, RBTDRC_ARK_BASENAME_VOUCH, hallmark
2545	        );
2546	
2547	        let _ = std::fs::write(dir.join("03-run.txt"), "running");
2548	        match rbtdrc_docker_run(&image_ref) {
2549	            Ok((output, 0)) if output.contains(RBTDRC_FOURMODE_BUSYBOX_RUN_OUTPUT) => {}
2550	            Ok((output, code)) => {
2551	                return rbtdre_Verdict::Fail(format!(
2552	                    "run: expected '{}', got exit {} output: {}",
