2562	        let _ = std::fs::write(dir.join("04-summon.txt"), "summoning");
2563	        let summon_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_SUMMON, &[&hallmark], &[]) {
2564	            Ok(r) if r.exit_code == 0 => r,
2565	            Ok(r) => return rbtdre_Verdict::Fail(format!("summon failed (exit {})\n{}", r.exit_code, r.stderr)),
2566	            Err(e) => return rbtdre_Verdict::Fail(format!("summon invocation: {}", e)),
2567	        };
2568	        let _ = std::fs::write(dir.join("04-summon-stdout.txt"), &summon_result.stdout);
2569	        for ark_ref in [&image_ref, &about_ref, &vouch_ref] {
2570	            if !rbtdrc_docker_inspect(ark_ref) {
2571	                return rbtdre_Verdict::Fail(format!("summon: ark not local after pull: {}", ark_ref));
2572	            }
2573	        }
2574	
2575	        // Plumb full — verify provenance display contains SLSA / SBOM / Dockerfile.
2576	        let _ = std::fs::write(dir.join("05-plumb-full.txt"), "plumbing full");
2577	        let plumb_full_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_PLUMB_FULL, &[&hallmark], &[]) {
2578	            Ok(r) if r.exit_code == 0 => r,
2579	            Ok(r) => return rbtdre_Verdict::Fail(format!("plumb_full failed (exit {})\n{}", r.exit_code, r.stderr)),
2580	            Err(e) => return rbtdre_Verdict::Fail(format!("plumb_full invocation: {}", e)),
2581	        };
2582	        let _ = std::fs::write(dir.join("05-plumb-full-stdout.txt"), &plumb_full_result.stdout);
2583	        for marker in ["SLSA", "SBOM", "Dockerfile"] {
2584	            if !plumb_full_result.stdout.contains(marker) {
2585	                return rbtdre_Verdict::Fail(format!(
2586	                    "plumb_full: marker '{}' not in stdout",
2587	                    marker
2588	                ));
2589	            }
2590	        }
2591	
2592	        // Rekon — verify image+about+vouch basenames are present.
2593	        let _ = std::fs::write(dir.join("06-rekon.txt"), "rekoning");
2594	        let rekon_result = match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_REKON_HALLMARK, &[&hallmark], &[]) {
2595	            Ok(r) if r.exit_code == 0 => r,
2596	            Ok(r) => return rbtdre_Verdict::Fail(format!("rekon failed (exit {})\n{}", r.exit_code, r.stderr)),
2597	            Err(e) => return rbtdre_Verdict::Fail(format!("rekon invocation: {}", e)),
2598	        };
2599	        let _ = std::fs::write(dir.join("06-rekon-stdout.txt"), &rekon_result.stdout);
2600	        for basename in [
2601	            RBTDRC_ARK_BASENAME_IMAGE,
2602	            RBTDRC_ARK_BASENAME_ABOUT,
2603	            RBTDRC_ARK_BASENAME_VOUCH,
2604	            RBTDRC_ARK_BASENAME_ATTEST,
2605	        ] {
2606	            if !rbtdrc_rekon_basename_yes(&rekon_result.stdout, basename) {
2607	                return rbtdre_Verdict::Fail(format!(
2608	                    "rekon: basename '{}' not marked yes\nstdout:\n{}",
2609	                    basename, rekon_result.stdout
2610	                ));
2611	            }
2612	        }
2613	
2614	        if let Err(e) = rbtdrc_docker_rmi(&[&image_ref, &about_ref, &vouch_ref]) {
2615	            return rbtdre_Verdict::Fail(format!("rmi: {}", e));
2616	        }
2617	
2618	        let _ = std::fs::write(dir.join("07-abjure.txt"), "abjuring");
2619	        match rbtdri_invoke_global(ctx, RBTDRM_COLOPHON_ABJURE, &[&hallmark], &[(RBTDRI_BURE_CONFIRM_KEY, RBTDRI_BURE_CONFIRM_SKIP)]) {
2620	            Ok(r) if r.exit_code == 0 => {}
2621	            Ok(r) => return rbtdre_Verdict::Fail(format!("abjure failed (exit {})\n{}", r.exit_code, r.stderr)),
2622	            Err(e) => return rbtdre_Verdict::Fail(format!("abjure invocation: {}", e)),
2623	        }
2624	
2625	        let _ = std::fs::write(dir.join("08-passed.txt"), "passed");
2626	        rbtdre_Verdict::Pass
2627	    })
2628	}
