2783	        };
2784	        let hallmark = match rbtdri_read_burv_fact(&ordain_result, RBTDRC_FACT_HALLMARK) {
2785	            Ok(v) => v,
2786	            Err(e) => return rbtdre_Verdict::Fail(format!("read hallmark: {}", e)),
2787	        };
