2798	        let _ = std::fs::write(dir.join("03-wrest.txt"), "wresting");
2799	        let locator = format!(
2800	            "{}/{}/{}:{}",
2801	            RBTDRC_GAR_CATEGORY_HALLMARKS, hallmark, RBTDRC_ARK_BASENAME_IMAGE, hallmark
2802	        );
