15	// Author: Brad Hyslop <bhyslop@scaleinvariant.org>
16	//
17	// RBTDRO — gauntlet onboarding-sequence fixture (§3 of release qualification)
18	//
19	// Each case walks the operator-facing onboarding handbook track for one
20	// vessel-construction mode, invoking the handbook's prescribed tabtargets
21	// in the prescribed order. Case order and per-case docs live with the
22	// functions below; the registered order is the source of truth (see the
23	// `cases:` array in RBTDRO_SECTIONS_ONBOARDING_SEQUENCE).
24	//
25	// Disposition: StateProgressing. Build-only — no charge, no test. Cases stop
26	// when each handbook-prescribed hallmark lands in GAR. Per-case precondition
27	// probes enable a-la-carte single-case rerun.
28	//
29	// inscribe_reliquary yokes the reliquary stamp into vessel rbrv.env files
30	// and commits. Downstream cases verify it ran by reading RBRV_RELIQUARY from
31	// a stable yoked vessel's rbrv.env — no out-of-source-tree scratch state.
32	
33	use std::io::{BufRead, BufReader, Write};
34	use std::path::{Path, PathBuf};
35	
36	use crate::case;
37	use crate::rbtdrb_probe::{rbtdrb_assert, rbtdrb_Probe};
38	use crate::rbtdrc_crucible::{rbtdrc_with_ctx, RBTDRC_FACT_HALLMARK, RBTDRC_FACT_RELIQUARY};
39	use crate::rbtdre_engine::{rbtdre_Disposition, rbtdre_Fixture, rbtdre_Section, rbtdre_Verdict};
40	use crate::rbtdri_invocation::{
41	    rbtdri_invoke_global, rbtdri_read_burv_fact, rbtdri_Context, rbtdri_InvokeResult,
42	};
43	use crate::rbtdrk_canonical::rbtdrk_canonical_rbra;
44	use crate::rbtdrm_manifest::{
45	    RBTDRM_COLOPHON_ENSHRINE_VESSEL, RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
46	    RBTDRM_COLOPHON_KLUDGE_BOTTLE, RBTDRM_COLOPHON_KLUDGE_SENTRY, RBTDRM_COLOPHON_ORDAIN,
47	    RBTDRM_COLOPHON_YOKE_RELIQUARY, RBTDRM_CONTAINER_BOTTLE, RBTDRM_CONTAINER_SENTRY,
48	    RBTDRM_FIXTURE_ONBOARDING_SEQUENCE, RBTDRM_OPERATION_ENSHRINE, RBTDRM_OPERATION_INSCRIBE,
49	    RBTDRM_OPERATION_KLUDGE, RBTDRM_OPERATION_ORDAIN, RBTDRM_OPERATION_YOKE,
50	};
51	
52	// ── Vessel directories ────────────────────────────────────────
53	
54	const RBTDRO_VESSEL_DIR_SENTRY_TETHER: &str = "rbev-vessels/rbev-sentry-deb-tether";
55	const RBTDRO_VESSEL_DIR_AIRGAP_FORGE: &str = "rbev-vessels/rbev-bottle-ifrit-forge";
56	const RBTDRO_VESSEL_DIR_AIRGAP_BOTTLE: &str = "rbev-vessels/rbev-bottle-ifrit-airgap";
57	const RBTDRO_VESSEL_DIR_PLANTUML: &str = "rbev-vessels/rbev-bottle-plantuml";
58	const RBTDRO_VESSEL_DIR_JUPYTER: &str = "rbev-vessels/rbev-bottle-anthropic-jupyter";
59	const RBTDRO_VESSEL_DIR_GRAFT: &str = "rbev-vessels/rbev-graft-demo";
60	
61	// ── Nameplate monikers ────────────────────────────────────────
62	
63	const RBTDRO_NAMEPLATE_TADMOR: &str = "tadmor";
64	const RBTDRO_NAMEPLATE_CCYOLO: &str = "ccyolo";
65	const RBTDRO_NAMEPLATE_MORIAH: &str = "moriah";
66	const RBTDRO_NAMEPLATE_SRJCL: &str = "srjcl";
67	const RBTDRO_NAMEPLATE_PLUML: &str = "pluml";
68	
69	// ── Nameplate hallmark variable names (lines in .rbk/<nameplate>/rbrn.env) ──
70	
71	const RBTDRO_HALLMARK_VAR_BOTTLE: &str = "RBRN_BOTTLE_HALLMARK";
72	const RBTDRO_HALLMARK_VAR_SENTRY: &str = "RBRN_SENTRY_HALLMARK";
73	
74	// ── Consumer arrays ───────────────────────────────────────────
75	
76	/// Nameplates that receive the sentry-tether hallmark from ordain-conjure.
77	const RBTDRO_CONSUMERS_SENTRY_TETHER: &[&str] = &[
78	    RBTDRO_NAMEPLATE_MORIAH,
79	    RBTDRO_NAMEPLATE_SRJCL,
80	    RBTDRO_NAMEPLATE_PLUML,
81	];
82	
83	/// Nameplates that receive the airgap-bottle hallmark from ordain-airgap.
84	const RBTDRO_CONSUMERS_AIRGAP_BOTTLE: &[&str] = &[RBTDRO_NAMEPLATE_MORIAH];
85	
86	/// Nameplates that receive the plantuml-bottle hallmark from ordain-bind.
87	const RBTDRO_CONSUMERS_PLANTUML_BOTTLE: &[&str] = &[RBTDRO_NAMEPLATE_PLUML];
88	
89	/// Nameplates that receive the jupyter-bottle hallmark from conjure-srjcl.
90	const RBTDRO_CONSUMERS_JUPYTER_BOTTLE: &[&str] = &[RBTDRO_NAMEPLATE_SRJCL];
91	
92	// ── Hallmark-base locator construction ───────────────────────
93	//
94	// Module-local literals matching rbgc_Constants.sh values. Used to compose the
95	// airgap-bottle's RBRV_IMAGE_1_ANCHOR after the forge hallmark is captured.
96	// Orchestration writes a hallmark-namespace locator directly into the consumer
97	// vessel's rbrv.env; conjure resolves the locator at airgap-bottle build time.
98	// The forge hallmark's existence in GAR is established by ordain-forge's
99	// success — no separate enshrine validation step on the consumer.
100	
101	const RBTDRO_GAR_CATEGORY_HALLMARKS: &str = "rbi_hm";
102	const RBTDRO_ARK_BASENAME_IMAGE: &str = "image";
103	
104	/// Slot 1 of the airgap-bottle vessel — the only base-image slot the airgap
105	/// supply chain populates from a hallmark.
106	const RBTDRO_AIRGAP_BASE_ANCHOR_VAR: &str = "RBRV_IMAGE_1_ANCHOR";
107	
108	// ── Reliquary stamp witness ──────────────────────────────────
109	
110	/// Filename of a vessel's rbrv.env (relative to the vessel directory).
111	const RBTDRO_VESSEL_RBRV_FILE: &str = "rbrv.env";
112	
113	/// Field name yoked by case 1 in each vessel rbrv.env. Presence (non-empty)
114	/// is the cross-case witness that case 1 ran.
115	const RBTDRO_FIELD_RBRV_RELIQUARY: &str = "RBRV_RELIQUARY";
116	
117	/// Stable vessel chosen for the case-1 witness probe. Yoke is wildcard-
118	/// fan-out across every vessel under ${RBRR_VESSEL_DIR}; sentry-tether is a
119	/// guaranteed-present member of that set, so its rbrv.env always carries
120	/// the stamp after case 1.
121	const RBTDRO_WITNESS_VESSEL_DIR: &str = RBTDRO_VESSEL_DIR_SENTRY_TETHER;
122	
123	// ── Graft override ───────────────────────────────────────────
124	
125	/// BURE_TWEAK signal recognized by rbfd_FoundryDirectorBuild for graft mode:
126	/// supplies the local image reference without mutating the vessel rbrv.env.
127	const RBTDRO_GRAFT_TWEAK_NAME: &str = "threemodegraft";
128	
129	/// Source image for graft: any locally-resolvable docker image works; an
130	/// upstream public image keeps this case independent of the conjure case.
131	const RBTDRO_GRAFT_SOURCE_IMAGE: &str = "busybox:latest";
132	
133	// ── Probes ───────────────────────────────────────────────────
134	//
135	// Probes are pure `fn() -> Result<(), String>` per the rbtdrb_Probe shape and
136	// have no context, so they read the project root from current_dir() — theurge
137	// always launches from the project root.
138	
139	fn rbtdro_probe_root() -> Result<PathBuf, String> {
140	    std::env::current_dir().map_err(|e| format!("cannot resolve project root: {}", e))
141	}
142	
143	/// Read an env-file value or None if absent. Mirrors the helpers in rbtdrk
144	/// and rbtdrp — kept local to avoid cross-module coupling.
145	fn rbtdro_read_env_value(path: &Path, key: &str) -> Option<String> {
146	    let content = std::fs::read_to_string(path).ok()?;
147	    let prefix = format!("{}=", key);
148	    for line in content.lines() {
149	        let trimmed = line.trim_start();
150	        if trimmed.starts_with('#') {
151	            continue;
152	        }
153	        if let Some(rest) = trimmed.strip_prefix(&prefix) {
154	            return Some(rest.to_string());
155	        }
156	    }
157	    None
158	}
159	
160	/// Cases 1, 2, 8, 9 probe: governor RBRA present at the canonical secrets path.
161	/// Established by canonical-establish §2 (rbtdrk_governor_mantle).
162	fn rbtdro_probe_governor_rbra() -> Result<(), String> {
163	    let root = rbtdro_probe_root()?;
164	    let path = rbtdrk_canonical_rbra(&root, "governor")?;
165	    if !path.exists() {
166	        return Err(format!("governor RBRA absent at {}", path.display()));
167	    }
168	    Ok(())
169	}
170	
171	/// Cases 3-7 probe: reliquary stamp yoked into the witness vessel's rbrv.env.
172	/// Case 1's yoke fan-out writes RBRV_RELIQUARY into every ordain-path vessel
173	/// and commits; reading the witness vessel's committed value is the cross-case
174	/// evidence that case 1 ran. No out-of-source-tree scratch state.
175	/// Kludge is local-only (no GCP), so governor RBRA is not a load-bearing
176	/// precondition for kludge; the witness presence confirms case 1 completed.
177	fn rbtdro_probe_reliquary_stamp() -> Result<(), String> {
178	    let root = rbtdro_probe_root()?;
179	    let rbrv = root
180	        .join(RBTDRO_WITNESS_VESSEL_DIR)
181	        .join(RBTDRO_VESSEL_RBRV_FILE);
182	    let value = rbtdro_read_env_value(&rbrv, RBTDRO_FIELD_RBRV_RELIQUARY).ok_or_else(|| {
183	        format!(
184	            "{} missing from {}",
185	            RBTDRO_FIELD_RBRV_RELIQUARY,
186	            rbrv.display()
187	        )
188	    })?;
189	    if value.trim().is_empty() {
190	        return Err(format!(
191	            "{} is empty in {}",
192	            RBTDRO_FIELD_RBRV_RELIQUARY,
193	            rbrv.display()
194	        ));
195	    }
196	    Ok(())
197	}
198	
199	// ── Helpers ──────────────────────────────────────────────────
200	
201	fn rbtdro_invoke_logged(
202	    ctx: &mut rbtdri_Context,
203	    colophon: &str,
204	    args: &[&str],
205	    extra_env: &[(&str, &str)],
206	    dir: &Path,
207	    label: &str,
208	) -> Result<rbtdri_InvokeResult, String> {
209	    let result = rbtdri_invoke_global(ctx, colophon, args, extra_env)?;
210	    let _ = std::fs::write(dir.join(format!("{}-stdout.txt", label)), &result.stdout);
211	    let _ = std::fs::write(dir.join(format!("{}-stderr.txt", label)), &result.stderr);
212	    Ok(result)
213	}
214	
215	/// Invoke a tabtarget via `rbtdro_invoke_logged` and convert non-success outcomes
216	/// into Fail verdicts with consistent operation-prefixed messages. `target` is
217	/// the per-call distinguishing string (vessel sigil, vessel dir, nameplate)
218	/// included in the error prefix; pass `""` for operations without a target.
219	fn rbtdro_invoke_or_fail(
220	    ctx: &mut rbtdri_Context,
221	    operation: &str,
222	    target: &str,
223	    colophon: &str,
224	    args: &[&str],
225	    extra_env: &[(&str, &str)],
226	    dir: &Path,
227	    label: &str,
228	) -> Result<rbtdri_InvokeResult, rbtdre_Verdict> {
229	    let prefix = if target.is_empty() {
230	        operation.to_string()
231	    } else {
232	        format!("{} {}", operation, target)
233	    };
234	    let result = rbtdro_invoke_logged(ctx, colophon, args, extra_env, dir, label)
235	        .map_err(|e| rbtdre_Verdict::Fail(format!("{} invocation: {}", prefix, e)))?;
236	    if result.exit_code != 0 {
237	        return Err(rbtdre_Verdict::Fail(format!(
238	            "{} exit {}\n{}",
239	            prefix, result.exit_code, result.stderr
240	        )));
241	    }
242	    Ok(result)
243	}
244	
245	/// Run an ordain on `vessel_dir` and return the captured hallmark string.
246	/// Writes invocation logs to `dir` under the `label` prefix; returns Fail
247	/// verdict-bearing Err so callers can early-return cleanly.
248	fn rbtdro_ordain_capture(
249	    ctx: &mut rbtdri_Context,
250	    dir: &Path,
251	    vessel_dir: &str,
252	    extra_env: &[(&str, &str)],
253	    label: &str,
254	) -> Result<String, rbtdre_Verdict> {
255	    let result = rbtdro_invoke_or_fail(
256	        ctx,
257	        RBTDRM_OPERATION_ORDAIN,
258	        vessel_dir,
259	        RBTDRM_COLOPHON_ORDAIN,
260	        &[vessel_dir],
261	        extra_env,
262	        dir,
263	        label,
264	    )?;
265	    let hallmark = rbtdri_read_burv_fact(&result, RBTDRC_FACT_HALLMARK).map_err(|e| {
266	        rbtdre_Verdict::Fail(format!(
267	            "read hallmark fact after {} {}: {}",
268	            RBTDRM_OPERATION_ORDAIN, vessel_dir, e
269	        ))
270	    })?;
271	    let _ = std::fs::write(dir.join(format!("{}-hallmark.txt", label)), &hallmark);
272	    Ok(hallmark)
273	}
274	
275	/// Yoke the reliquary stamp into every vessel's rbrv.env. The yoke tabtarget
276	/// validates the stamp once against GAR, then wildcard-iterates every vessel
