339	/// Write a value into a vessel's rbrv.env. Same atomic-rename pattern as
340	/// rbtdro_drive_hallmark, but targeting the vessel's regime file rather than
341	/// a nameplate's. Returns Err if the variable line is not found.
342	fn rbtdro_write_vessel_env(
343	    root: &Path,
344	    vessel_dir: &str,
345	    var_name: &str,
346	    value: &str,
347	) -> Result<(), String> {
348	    let rbrv_path = root.join(vessel_dir).join(RBTDRO_VESSEL_RBRV_FILE);
349	    let file = std::fs::File::open(&rbrv_path)
350	        .map_err(|e| format!("open rbrv.env for {}: {}", vessel_dir, e))?;
351	
352	    let lines: Vec<String> = BufReader::new(file)
353	        .lines()
354	        .collect::<Result<_, _>>()
355	        .map_err(|e| format!("read rbrv.env for {}: {}", vessel_dir, e))?;
356	
357	    let prefix = format!("{}=", var_name);
358	    let mut found = false;
359	    let rewritten: Vec<String> = lines
360	        .into_iter()
361	        .map(|line| {
362	            if line.starts_with(&prefix) {
363	                found = true;
364	                format!("{}={}", var_name, value)
365	            } else {
366	                line
367	            }
368	        })
369	        .collect();
370	
371	    if !found {
372	        return Err(format!(
373	            "variable {} not found in {}/rbrv.env",
374	            var_name, vessel_dir
375	        ));
376	    }
377	
378	    let tmp_path = rbrv_path.with_extension("env.write_tmp");
379	    {
380	        let mut tmp = std::fs::File::create(&tmp_path)
381	            .map_err(|e| format!("create tmp rbrv.env for {}: {}", vessel_dir, e))?;
382	        for line in &rewritten {
383	            writeln!(tmp, "{}", line)
384	                .map_err(|e| format!("write tmp rbrv.env for {}: {}", vessel_dir, e))?;
385	        }
386	    }
387	    std::fs::rename(&tmp_path, &rbrv_path)
388	        .map_err(|e| format!("atomic replace rbrv.env for {}: {}", vessel_dir, e))?;
389	    Ok(())
390	}
