449	/// Auto-commit helper. Checks git status --porcelain; if the working tree is
450	/// clean, returns Ok without committing. Otherwise runs `git add -A` then
451	/// `git commit -m <message>`. Theurge launches from project root so no
452	/// explicit current_dir is needed.
453	fn rbtdro_git_commit(message: &str) -> Result<(), rbtdre_Verdict> {
454	    let status = std::process::Command::new("git")
455	        .args(["status", "--porcelain"])
456	        .output()
457	        .map_err(|e| {
458	            rbtdre_Verdict::Fail(format!("git status --porcelain exec failed: {}", e))
459	        })?;
460	    if !status.status.success() {
461	        return Err(rbtdre_Verdict::Fail(format!(
462	            "git status --porcelain exited {}",
463	            status.status.code().unwrap_or(-1)
464	        )));
465	    }
466	    let porcelain = String::from_utf8_lossy(&status.stdout);
467	    if porcelain.trim().is_empty() {
468	        // Nothing to commit — clean tree is not an error.
469	        return Ok(());
470	    }
471	
472	    let add = std::process::Command::new("git")
473	        .args(["add", "-A"])
474	        .output()
475	        .map_err(|e| rbtdre_Verdict::Fail(format!("git add -A exec failed: {}", e)))?;
476	    if !add.status.success() {
477	        return Err(rbtdre_Verdict::Fail(format!(
478	            "git add -A exited {}: {}",
479	            add.status.code().unwrap_or(-1),
480	            String::from_utf8_lossy(&add.stderr).trim()
481	        )));
482	    }
483	
484	    let commit = std::process::Command::new("git")
485	        .args(["commit", "-m", message])
486	        .output()
487	        .map_err(|e| rbtdre_Verdict::Fail(format!("git commit exec failed: {}", e)))?;
488	    if !commit.status.success() {
489	        return Err(rbtdre_Verdict::Fail(format!(
490	            "git commit exited {}: {}",
491	            commit.status.code().unwrap_or(-1),
492	            String::from_utf8_lossy(&commit.stderr).trim()
493	        )));
494	    }
495	    Ok(())
496	}
