543	/// Inscribe the depot-wide reliquary toolchain. Captures the reliquary
544	/// stamp from BURV fact, persists it to the fixture scratch file, then
545	/// yokes the stamp into all ordain-side vessels in one pass and auto-commits.
546	fn rbtdro_onboarding_inscribe_reliquary(dir: &Path) -> rbtdre_Verdict {
547	    let probe = rbtdrb_Probe {
548	        name: "governor RBRA present",
549	        check: rbtdro_probe_governor_rbra,
550	        remediation: "rerun canonical-establish (rbtdrk_governor_mantle) before this fixture",
551	    };
552	    if let Err(v) = rbtdrb_assert(&probe) {
553	        return v;
554	    }
555	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_inscribe_reliquary_impl(ctx, dir))
556	}
557	
558	fn rbtdro_onboarding_inscribe_reliquary_impl(
559	    ctx: &mut rbtdri_Context,
560	    dir: &Path,
561	) -> rbtdre_Verdict {
562	    let result = match rbtdro_invoke_or_fail(
563	        ctx,
564	        RBTDRM_OPERATION_INSCRIBE,
565	        "",
566	        RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
567	        &[],
568	        &[],
569	        dir,
570	        RBTDRM_OPERATION_INSCRIBE,
571	    ) {
572	        Ok(r) => r,
573	        Err(v) => return v,
574	    };
575	
576	    let stamp = match rbtdri_read_burv_fact(&result, RBTDRC_FACT_RELIQUARY) {
577	        Ok(s) => s,
578	        Err(e) => return rbtdre_Verdict::Fail(format!("read reliquary fact: {}", e)),
579	    };
580	    let _ = std::fs::write(dir.join("reliquary-stamp.txt"), &stamp);
581	
582	    // Wildcard-yoke: single invocation writes RBRV_RELIQUARY into every
583	    // vessel under ${RBRR_VESSEL_DIR}.
584	    if let Err(v) = rbtdro_yoke(ctx, dir, &stamp, RBTDRM_OPERATION_YOKE) {
585	        return v;
586	    }
587	
588	    // Commit the rbrv.env changes for all yoked vessels.
589	    if let Err(v) = rbtdro_git_commit(&format!(
590	        "inscribe-reliquary: {} stamp across all vessels",
591	        RBTDRM_OPERATION_YOKE
592	    )) {
593	        return v;
594	    }
595	
596	    rbtdre_Verdict::Pass
597	}
