740	/// airgap vessel's base anchor (no copy — orchestration writes the locator
741	/// directly), conjure the airgap bottle.
742	/// Case 1 yoked the reliquary stamp into both forge and airgap vessels.
743	/// Propagates airgap-bottle hallmark to moriah via RBRN_BOTTLE_HALLMARK.
744	fn rbtdro_onboarding_ordain_airgap(dir: &Path) -> rbtdre_Verdict {
745	    let probe = rbtdrb_Probe {
746	        name: "reliquary stamp captured",
747	        check: rbtdro_probe_reliquary_stamp,
748	        remediation: "rerun rbtdro_onboarding_inscribe_reliquary before this case",
749	    };
750	    if let Err(v) = rbtdrb_assert(&probe) {
751	        return v;
752	    }
753	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_ordain_airgap_impl(ctx, dir))
754	}
