756	fn rbtdro_onboarding_ordain_airgap_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
757	    let root = ctx.project_root().to_path_buf();
758	
759	    let forge_sigil = RBTDRO_VESSEL_DIR_AIRGAP_FORGE
760	        .rsplit('/')
761	        .next()
762	        .unwrap_or(RBTDRO_VESSEL_DIR_AIRGAP_FORGE);
763	
764	    if let Err(v) = rbtdro_enshrine(ctx, dir, forge_sigil, "enshrine-upstream") {
765	        return v;
766	    }
767	    // Commit before ordain-forge: ordain has clean-tree precondition.
768	    if let Err(v) = rbtdro_git_commit(
769	        "ordain-airgap: enshrine upstream rust base into forge vessel",
770	    ) {
771	        return v;
772	    }
773	
774	    // Capture the forge hallmark — it becomes the airgap-bottle's base via
775	    // a hallmark-namespace locator (mechanism (c)).
776	    let forge_hallmark = match rbtdro_ordain_capture(
777	        ctx,
778	        dir,
779	        RBTDRO_VESSEL_DIR_AIRGAP_FORGE,
780	        &[],
781	        "ordain-forge",
782	    ) {
783	        Ok(h) => h,
784	        Err(v) => return v,
785	    };
786	
787	    // Write the hallmark-base locator into airgap-bottle's rbrv.env. The slot
788	    // points at the forge image inside its hallmark subtree; conjure resolves
789	    // this locator to a full GAR ref at airgap-bottle build time.
790	    let airgap_anchor = format!(
791	        "{}/{}/{}:{}",
792	        RBTDRO_GAR_CATEGORY_HALLMARKS,
793	        forge_hallmark.trim(),
794	        RBTDRO_ARK_BASENAME_IMAGE,
795	        forge_hallmark.trim(),
796	    );
797	    if let Err(e) = rbtdro_write_vessel_env(
798	        &root,
799	        RBTDRO_VESSEL_DIR_AIRGAP_BOTTLE,
800	        RBTDRO_AIRGAP_BASE_ANCHOR_VAR,
801	        &airgap_anchor,
802	    ) {
803	        return rbtdre_Verdict::Fail(format!("write airgap-bottle anchor: {}", e));
804	    }
805	    let _ = std::fs::write(dir.join("airgap-anchor.txt"), &airgap_anchor);
806	
807	    // Commit the locator write before ordain-airgap: ordain has clean-tree
808	    // precondition. The forge hallmark's existence in GAR is established by
809	    // ordain-forge's success above — no separate enshrine validation step.
810	    if let Err(v) = rbtdro_git_commit(
811	        "ordain-airgap: write forge-hallmark locator into airgap-bottle base anchor",
812	    ) {
813	        return v;
814	    }
815	
816	    let airgap_hallmark = match rbtdro_ordain_capture(
817	        ctx,
818	        dir,
819	        RBTDRO_VESSEL_DIR_AIRGAP_BOTTLE,
820	        &[],
821	        "ordain-airgap",
822	    ) {
823	        Ok(h) => h,
824	        Err(v) => return v,
825	    };
826	
827	    for nameplate in RBTDRO_CONSUMERS_AIRGAP_BOTTLE {
828	        if let Err(e) =
829	            rbtdro_drive_hallmark(&root, nameplate, RBTDRO_HALLMARK_VAR_BOTTLE, &airgap_hallmark)
830	        {
831	            return rbtdre_Verdict::Fail(format!(
832	                "drive airgap hallmark into {}: {}",
833	                nameplate, e
834	            ));
835	        }
836	    }
837	
838	    if let Err(v) =
839	        rbtdro_git_commit("ordain-airgap: airgap-bottle hallmark + propagate to moriah")
840	    {
841	        return v;
842	    }
843	
844	    rbtdre_Verdict::Pass
845	}
846	
847	/// Pin upstream PlantUML by digest. Bind mode reads RBRV_BIND_IMAGE from
848	/// rbev-bottle-plantuml/rbrv.env and mirrors the digest into GAR via Cloud
849	/// Build (skopeo from reliquary + about/vouch metadata). Propagates plantuml
850	/// hallmark to pluml via RBRN_BOTTLE_HALLMARK.
851	fn rbtdro_onboarding_ordain_bind(dir: &Path) -> rbtdre_Verdict {
852	    let probe = rbtdrb_Probe {
853	        name: "reliquary stamp captured",
854	        check: rbtdro_probe_reliquary_stamp,
855	        remediation: "rerun rbtdro_onboarding_inscribe_reliquary before this case",
856	    };
857	    if let Err(v) = rbtdrb_assert(&probe) {
858	        return v;
859	    }
860	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_ordain_bind_impl(ctx, dir))
861	}
862	
863	fn rbtdro_onboarding_ordain_bind_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
864	    let root = ctx.project_root().to_path_buf();
865	
866	    let hallmark = match rbtdro_ordain_capture(
867	        ctx,
868	        dir,
869	        RBTDRO_VESSEL_DIR_PLANTUML,
870	        &[],
871	        "ordain-bind",
872	    ) {
873	        Ok(h) => h,
874	        Err(v) => return v,
875	    };
876	
877	    for nameplate in RBTDRO_CONSUMERS_PLANTUML_BOTTLE {
878	        if let Err(e) =
879	            rbtdro_drive_hallmark(&root, nameplate, RBTDRO_HALLMARK_VAR_BOTTLE, &hallmark)
880	        {
881	            return rbtdre_Verdict::Fail(format!(
882	                "drive plantuml hallmark into {}: {}",
883	                nameplate, e
884	            ));
885	        }
886	    }
887	
888	    if let Err(v) =
889	        rbtdro_git_commit("ordain-bind: plantuml-bottle hallmark + propagate to pluml")
890	    {
891	        return v;
892	    }
893	
894	    rbtdre_Verdict::Pass
895	}
896	
897	/// Pull the graft source image, then ordain rbev-graft-demo with a
898	/// BURE_TWEAK overriding RBRV_GRAFT_IMAGE in-process. No consumers —
899	/// graft-demo is terminal.
900	fn rbtdro_onboarding_ordain_graft(dir: &Path) -> rbtdre_Verdict {
901	    let probe = rbtdrb_Probe {
902	        name: "reliquary stamp captured",
903	        check: rbtdro_probe_reliquary_stamp,
904	        remediation: "rerun rbtdro_onboarding_inscribe_reliquary before this case",
905	    };
906	    if let Err(v) = rbtdrb_assert(&probe) {
907	        return v;
908	    }
909	    rbtdrc_with_ctx(|ctx| rbtdro_onboarding_ordain_graft_impl(ctx, dir))
910	}
911	
912	fn rbtdro_onboarding_ordain_graft_impl(ctx: &mut rbtdri_Context, dir: &Path) -> rbtdre_Verdict {
913	    if let Err(e) = rbtdro_docker_pull(RBTDRO_GRAFT_SOURCE_IMAGE) {
914	        return rbtdre_Verdict::Fail(format!(
915	            "docker pull {}: {}",
916	            RBTDRO_GRAFT_SOURCE_IMAGE, e
917	        ));
918	    }
919	    let extra_env: &[(&str, &str)] = &[
920	        ("BURE_TWEAK_NAME", RBTDRO_GRAFT_TWEAK_NAME),
921	        ("BURE_TWEAK_VALUE", RBTDRO_GRAFT_SOURCE_IMAGE),
922	    ];
923	    let hallmark = match rbtdro_ordain_capture(
924	        ctx,
925	        dir,
926	        RBTDRO_VESSEL_DIR_GRAFT,
927	        extra_env,
928	        "ordain-graft",
929	    ) {
930	        Ok(h) => h,
931	        Err(v) => return v,
932	    };
933	    let _ = hallmark; // graft-demo is terminal — no consumer propagation
934	
935	    if let Err(v) = rbtdro_git_commit("ordain-graft: graft-demo hallmark") {
936	        return v;
937	    }
938	
939	    rbtdre_Verdict::Pass
940	}
941	
942	// ── Section registry ─────────────────────────────────────────
943	
944	pub static RBTDRO_SECTIONS_ONBOARDING_SEQUENCE: &[rbtdre_Section] = &[rbtdre_Section {
945	    name: "onboarding-arc",
946	    cases: &[
947	        case!(rbtdro_onboarding_inscribe_reliquary),
948	        case!(rbtdro_onboarding_kludge_tadmor),
949	        case!(rbtdro_onboarding_kludge_ccyolo),
950	        case!(rbtdro_onboarding_ordain_conjure),
951	        case!(rbtdro_onboarding_conjure_srjcl),
952	        case!(rbtdro_onboarding_ordain_airgap),
953	        case!(rbtdro_onboarding_ordain_bind),
954	        case!(rbtdro_onboarding_ordain_graft),
955	    ],
956	}];
957	
958	pub static RBTDRO_FIXTURE_ONBOARDING_SEQUENCE: rbtdre_Fixture = rbtdre_Fixture {
959	    name: RBTDRM_FIXTURE_ONBOARDING_SEQUENCE,
960	    disposition: rbtdre_Disposition::StateProgressing,
961	    setup: None,
962	    teardown: None,
963	    sections: RBTDRO_SECTIONS_ONBOARDING_SEQUENCE,
964	};
