55	pub const RBTDRM_COLOPHON_KLUDGE_SENTRY: &str = "rbw-cKS";
56	pub const RBTDRM_COLOPHON_KLUDGE_BOTTLE: &str = "rbw-cKB";
57	
58	// Crucible active check (param1 channel — nameplate as argument)
59	pub const RBTDRM_COLOPHON_CRUCIBLE_ACTIVE: &str = "rbw-cic";
60	
61	// Access probe colophon (imprint-scoped by role)
62	pub const RBTDRM_COLOPHON_ACCESS_PROBE: &str = "rbtd-ap";
63	
64	// Payor depot colophons (global — no nameplate imprint)
65	pub const RBTDRM_COLOPHON_DEPOT_LEVY: &str = "rbw-dL";
66	pub const RBTDRM_COLOPHON_DEPOT_LIST: &str = "rbw-dl";
67	pub const RBTDRM_COLOPHON_DEPOT_UNMAKE: &str = "rbw-dU";
68	
69	// Director depot colophons — reliquary inscribe/yoke and vessel enshrine
70	// (global — no nameplate imprint)
71	pub const RBTDRM_COLOPHON_INSCRIBE_RELIQUARY: &str = "rbw-dI";
72	pub const RBTDRM_COLOPHON_YOKE_RELIQUARY: &str = "rbw-dY";
73	pub const RBTDRM_COLOPHON_ENSHRINE_VESSEL: &str = "rbw-dE";
74	
75	// Governor service-account colophons (global — no nameplate imprint)
76	pub const RBTDRM_COLOPHON_GOV_MANTLE: &str = "rbw-aM";
77	pub const RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER: &str = "rbw-arI";
78	pub const RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR: &str = "rbw-adI";
79	pub const RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER: &str = "rbw-arD";
80	pub const RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR: &str = "rbw-adD";
81	
82	// Handbook display colophons — one symbolic ref per RBZ_* zipper constant.
83	// Onboarding group (8)
84	pub const RBTDRM_COLOPHON_ONBOARD_START_HERE: &str = "rbw-o";
85	pub const RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE: &str = "rbw-Occ";
86	pub const RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER: &str = "rbw-Ocr";
87	pub const RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR: &str = "rbw-Ocd";
88	pub const RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE: &str = "rbw-Ofc";
89	pub const RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD: &str = "rbw-Odf";
90	pub const RBTDRM_COLOPHON_ONBOARD_PAYOR_HB: &str = "rbw-Op";
91	pub const RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB: &str = "rbw-Og";
92	// Windows group (4 of 5 — rbw-HWdw uses param1 channel, deferred to ₢A-AAS)
93	pub const RBTDRM_COLOPHON_HANDBOOK_TOP: &str = "rbw-h0";
94	pub const RBTDRM_COLOPHON_HANDBOOK_WINDOWS: &str = "rbw-hw";
95	pub const RBTDRM_COLOPHON_HW_DOCKER_DESKTOP: &str = "rbw-HWdd";
96	pub const RBTDRM_COLOPHON_HW_DOCKER_CONTEXT: &str = "rbw-HWdc";
