98	pub const RBTDRM_COLOPHON_PAYOR_ESTABLISH: &str = "rbw-gPE";
99	pub const RBTDRM_COLOPHON_PAYOR_REFRESH: &str = "rbw-gPR";
100	pub const RBTDRM_COLOPHON_QUOTA_BUILD: &str = "rbw-gq";
101	
102	// Fixture name consts — single definition per String Boundary Discipline.
103	// Crucible fixtures (charge/quench lifecycle)
104	pub const RBTDRM_FIXTURE_TADMOR: &str = "tadmor";
105	pub const RBTDRM_FIXTURE_MORIAH: &str = "moriah";
106	pub const RBTDRM_FIXTURE_SRJCL: &str = "srjcl";
107	pub const RBTDRM_FIXTURE_PLUML: &str = "pluml";
108	// Bare fixtures (GCP credentials, no container runtime)
109	pub const RBTDRM_FIXTURE_FOUR_MODE: &str = "four-mode";
110	pub const RBTDRM_FIXTURE_BATCH_VOUCH: &str = "batch-vouch";
111	pub const RBTDRM_FIXTURE_ACCESS_PROBE: &str = "access-probe";
112	// Fast fixtures (no external dependencies)
113	pub const RBTDRM_FIXTURE_ENROLLMENT_VALIDATION: &str = "enrollment-validation";
114	pub const RBTDRM_FIXTURE_REGIME_VALIDATION: &str = "regime-validation";
115	pub const RBTDRM_FIXTURE_REGIME_SMOKE: &str = "regime-smoke";
116	pub const RBTDRM_FIXTURE_HANDBOOK_RENDER: &str = "handbook-render";
117	// Pristine-lifecycle fixture (gate + SA/depot lifecycle cases)
118	pub const RBTDRM_FIXTURE_PRISTINE_LIFECYCLE: &str = "pristine-lifecycle";
119	// Gauntlet canonical-establish fixture (§2: canonical depot levy + governor
120	// mantle + retriever/director invest with per-case precondition probes)
121	pub const RBTDRM_FIXTURE_CANONICAL_ESTABLISH: &str = "canonical-establish";
122	// Gauntlet onboarding-sequence fixture (§3: handbook-walked vessel
123	// construction — inscribe reliquary, enshrine bases, kludge tadmor/ccyolo,
124	// plus one ordain-* case per director-mode handbook track, build-only)
125	pub const RBTDRM_FIXTURE_ONBOARDING_SEQUENCE: &str = "onboarding-sequence";
126	// Calibrant fixtures — synthetic deterministic-verdict fixtures driving the
127	// bash blackbox testbench. Internal framework-test plumbing.
128	pub const RBTDRM_FIXTURE_CALIBRANT_VERDICTS: &str = "calibrant-verdicts";
129	pub const RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST: &str = "calibrant-fail-fast";
130	pub const RBTDRM_FIXTURE_CALIBRANT_PROGRESSING: &str = "calibrant-progressing";
131	pub const RBTDRM_FIXTURE_CALIBRANT_SENTINEL: &str = "calibrant-sentinel";
132	
133	// Operation verb consts — single definition per String Boundary Discipline.
134	// Used for error-message prefixes, log labels, and commit messages where the
135	// operation name is a vocabulary unit. Atomic — compound operations like
136	// "kludge sentry" are composed at the call site from RBTDRM_OPERATION_KLUDGE
137	// and the relevant container-role constant.
138	pub const RBTDRM_OPERATION_INSCRIBE: &str = "inscribe";
139	pub const RBTDRM_OPERATION_YOKE: &str = "yoke";
140	pub const RBTDRM_OPERATION_ORDAIN: &str = "ordain";
141	pub const RBTDRM_OPERATION_ENSHRINE: &str = "enshrine";
142	pub const RBTDRM_OPERATION_KLUDGE: &str = "kludge";
143	
144	// Container role consts — sentry (security gateway) and bottle (workload) are
145	// the two container roles within a crucible. Used as suffixes for kludge
146	// operations and as commit-message vocabulary distinguishing the two builds.
147	pub const RBTDRM_CONTAINER_SENTRY: &str = "sentry";
148	pub const RBTDRM_CONTAINER_BOTTLE: &str = "bottle";
149	
150	/// Per-fixture required colophons. Returns None for unknown fixtures.
151	pub fn rbtdrm_required_colophons(fixture: &str) -> Option<&'static [&'static str]> {
152	    match fixture {
153	        RBTDRM_FIXTURE_TADMOR
154	        | RBTDRM_FIXTURE_MORIAH
155	        | RBTDRM_FIXTURE_SRJCL
156	        | RBTDRM_FIXTURE_PLUML => Some(&[
157	            RBTDRM_COLOPHON_CHARGE,
158	            RBTDRM_COLOPHON_QUENCH,
159	            RBTDRM_COLOPHON_WRIT,
160	            RBTDRM_COLOPHON_FIAT,
161	            RBTDRM_COLOPHON_BARK,
162	            RBTDRM_COLOPHON_CRUCIBLE_ACTIVE,
163	        ]),
164	        RBTDRM_FIXTURE_FOUR_MODE => Some(&[
165	            RBTDRM_COLOPHON_ORDAIN,
166	            RBTDRM_COLOPHON_ABJURE,
167	            RBTDRM_COLOPHON_WREST_HALLMARK_IMAGE,
168	            RBTDRM_COLOPHON_KLUDGE,
169	            RBTDRM_COLOPHON_SUMMON,
170	            RBTDRM_COLOPHON_PLUMB_FULL,
171	            RBTDRM_COLOPHON_PLUMB_COMPACT,
172	            RBTDRM_COLOPHON_REKON_HALLMARK,
173	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
174	        ]),
175	        RBTDRM_FIXTURE_BATCH_VOUCH => Some(&[
176	            RBTDRM_COLOPHON_ORDAIN,
177	            RBTDRM_COLOPHON_ABJURE,
178	            RBTDRM_COLOPHON_JETTISON_HALLMARK_IMAGE,
179	            RBTDRM_COLOPHON_VOUCH,
180	            RBTDRM_COLOPHON_TALLY,
181	        ]),
182	        RBTDRM_FIXTURE_ACCESS_PROBE => Some(&[RBTDRM_COLOPHON_ACCESS_PROBE]),
183	        RBTDRM_FIXTURE_ENROLLMENT_VALIDATION
184	        | RBTDRM_FIXTURE_REGIME_VALIDATION
185	        | RBTDRM_FIXTURE_REGIME_SMOKE
186	        | RBTDRM_FIXTURE_CALIBRANT_VERDICTS
187	        | RBTDRM_FIXTURE_CALIBRANT_FAIL_FAST
188	        | RBTDRM_FIXTURE_CALIBRANT_PROGRESSING
189	        | RBTDRM_FIXTURE_CALIBRANT_SENTINEL => Some(&[]),
190	        RBTDRM_FIXTURE_PRISTINE_LIFECYCLE => Some(&[
191	            RBTDRM_COLOPHON_DEPOT_LEVY,
192	            RBTDRM_COLOPHON_DEPOT_LIST,
193	            RBTDRM_COLOPHON_DEPOT_UNMAKE,
194	            RBTDRM_COLOPHON_GOV_MANTLE,
195	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
196	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
197	            RBTDRM_COLOPHON_GOV_DIVEST_RETRIEVER,
198	            RBTDRM_COLOPHON_GOV_DIVEST_DIRECTOR,
199	            RBTDRM_COLOPHON_ACCESS_PROBE,
200	        ]),
201	        RBTDRM_FIXTURE_CANONICAL_ESTABLISH => Some(&[
202	            RBTDRM_COLOPHON_DEPOT_LEVY,
203	            RBTDRM_COLOPHON_DEPOT_LIST,
204	            RBTDRM_COLOPHON_GOV_MANTLE,
205	            RBTDRM_COLOPHON_GOV_INVEST_RETRIEVER,
206	            RBTDRM_COLOPHON_GOV_INVEST_DIRECTOR,
207	            RBTDRM_COLOPHON_ACCESS_PROBE,
208	        ]),
209	        RBTDRM_FIXTURE_ONBOARDING_SEQUENCE => Some(&[
210	            RBTDRM_COLOPHON_INSCRIBE_RELIQUARY,
211	            RBTDRM_COLOPHON_YOKE_RELIQUARY,
212	            RBTDRM_COLOPHON_ENSHRINE_VESSEL,
213	            RBTDRM_COLOPHON_ORDAIN,
214	            RBTDRM_COLOPHON_KLUDGE_SENTRY,
215	            RBTDRM_COLOPHON_KLUDGE_BOTTLE,
216	        ]),
217	        RBTDRM_FIXTURE_HANDBOOK_RENDER => Some(&[
218	            RBTDRM_COLOPHON_ONBOARD_START_HERE,
219	            RBTDRM_COLOPHON_ONBOARD_CRASH_COURSE,
220	            RBTDRM_COLOPHON_ONBOARD_CRED_RETRIEVER,
221	            RBTDRM_COLOPHON_ONBOARD_CRED_DIRECTOR,
222	            RBTDRM_COLOPHON_ONBOARD_FIRST_CRUCIBLE,
223	            RBTDRM_COLOPHON_ONBOARD_DIR_FIRST_BUILD,
224	            RBTDRM_COLOPHON_ONBOARD_PAYOR_HB,
225	            RBTDRM_COLOPHON_ONBOARD_GOVERNOR_HB,
226	            RBTDRM_COLOPHON_HANDBOOK_TOP,
227	            RBTDRM_COLOPHON_HANDBOOK_WINDOWS,
228	            RBTDRM_COLOPHON_HW_DOCKER_DESKTOP,
229	            RBTDRM_COLOPHON_HW_DOCKER_CONTEXT,
230	            RBTDRM_COLOPHON_PAYOR_ESTABLISH,
231	            RBTDRM_COLOPHON_PAYOR_REFRESH,
232	            RBTDRM_COLOPHON_QUOTA_BUILD,
233	        ]),
234	        _ => None,
235	    }
236	}
237	
238	/// Verify that all required colophons for a fixture appear in the zipper manifest string.
239	pub fn rbtdrm_verify(manifest: &str, fixture: &str) -> Result<(), String> {
240	    let required = match rbtdrm_required_colophons(fixture) {
241	        Some(r) => r,
242	        None => {
243	            return Err(format!(
244	                "rbtd: unknown fixture '{}' — not registered in manifest",
245	                fixture
246	            ));
247	        }
248	    };
249	    for colophon in required {
250	        let found = manifest.split_whitespace().any(|token| token == *colophon);
251	        if !found {
252	            return Err(format!(
253	                "rbtd: colophon '{}' not found in zipper manifest (fixture '{}')",
254	                colophon, fixture
255	            ));
256	        }
257	    }
258	    Ok(())
259	}
