/// Recognize a hallmark identifier — shape is `<lowercase letter><digits>-r<digits>`
/// (mode-letter + creation timestamp + reliquary stamp). Used to positively
/// match hallmark rows out of audit stdout, robust to interleaved BUW banner,
/// ANSI-coded log lines, and table chrome.
fn zrbtdrc_is_hallmark_id(s: &str) -> bool {
    let bytes = s.as_bytes();
    let dash_r = match s.find("-r") {
        Some(pos) if pos >= 2 => pos,
        _ => return false,
    };
    if !bytes[0].is_ascii_lowercase() {
        return false;
    }
    if !bytes[1..dash_r].iter().all(|b| b.is_ascii_digit()) {
        return false;
    }
    let after = dash_r + 2;
    if after >= bytes.len() {
        return false;
    }
    bytes[after..].iter().all(|b| b.is_ascii_digit())
}

/// Parse `rbw-iah` audit-hallmarks stdout and return a sorted Vec of hallmark
/// identifiers. Positively matches hallmark-shaped lines; everything else
/// (BUW pre-banner, ANSI-coded buc_step logs, table chrome, totals) is ignored.
fn zrbtdrc_audit_parse(stdout: &str) -> Vec<String> {
    let mut hallmarks: Vec<String> = stdout
        .lines()
        .map(|line| line.trim())
        .filter(|line| zrbtdrc_is_hallmark_id(line))
        .map(|line| line.to_string())
        .collect();
    hallmarks.sort();
    hallmarks
}

