    })?;
    let suffix = format!(".{}", extension);
    let mut roots: Vec<String> = entries
        .filter_map(|entry| entry.ok())
        .filter_map(|entry| entry.file_name().into_string().ok())
        .filter_map(|name| name.strip_suffix(&suffix).map(str::to_string))
        .collect();
    roots.sort();
    Ok(roots)
}

